/**
 * Represents a single diff in an application
 */
export type Diff = DiffBreaking | DiffNonBreaking;

export const DiffDiscriminator = {
  DiffBreaking: 'diff_breaking',
  DiffNonBreaking: 'diff_non_breaking'
} as const;

export function isDiffBreaking(obj: Diff): obj is DiffBreaking {
  return obj.type === 'diff_breaking';
}

export function isDiffNonBreaking(obj: Diff): obj is DiffNonBreaking {
  return obj.type === 'diff_non_breaking';
}

/**
 * Identifies the specific type of item that was indexed by search
 */
export type ItemDetail = ApplicationSummary;

export const ItemDetailDiscriminator = {
  ApplicationSummary: 'application_summary'
} as const;

export function isApplicationSummary(obj: ItemDetail): obj is ApplicationSummary {
  return obj.type === 'application_summary';
}

