  async createWatch(params: CreateWatchOptions): Promise<Watch> {
    const url = `${this.baseUrl}/watches`;

      const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...(params.headers || {}),
      },
      body: JSON.stringify(params.body),
    });

    if (response.status === 201) {
      const data = await response.json();
      return data;
    }

    if (response.status === 409) {
      throw new ErrorsResponse(response);
    }

    throw new ApiException(response, `Request failed with status ${response.status}`);

  }

  async deleteWatchByGuid(guid: string, options?: DeleteWatchByGuidOptions): Promise<void> {
    const url = `${this.baseUrl}/watches/${guid}`;

      const response = await fetch(url, {
      method: 'DELETE',
      headers: {
        'Content-Type': 'application/json',
        ...(options?.headers || {}),
      },
    });

    if (response.status === 204) {
      return;
    }

    if (response.status === 401) {
      throw new VoidResponse(response);
    }

    if (response.status === 404) {
      throw new VoidResponse(response);
    }

    throw new ApiException(response, `Request failed with status ${response.status}`);

  }

